const headers = $input.first().json.headers || {};
const provided = String(headers['x-webhook-secret'] || headers['X-Webhook-Secret'] || '').trim();
const expected = String($env.WEBHOOK_SECRET || '').trim();
const authorized = expected.length > 0 && provided === expected;
const body = $input.first().json.body ?? $input.first().json;
return [{ json: { authorized, body } }];

const body = $input.first().json.body || {};
const email = String(body.customer_email || '').trim();
const subject = String(body.subject || '').trim();
const text = String(body.body || '').trim();
const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const valid = Boolean(email && subject && text && emailRe.test(email));
const crypto = require('crypto');
const input_hash = valid
  ? crypto.createHash('sha256').update(`${email}|${subject}|${text}`).digest('hex')
  : null;
return [{
  json: {
    valid,
    customer_email: email,
    subject,
    body: text,
    external_id: body.external_id || null,
    source: 'webhook',
    input_hash
  }
}];

const ticket = $input.first().json;
const payload = $('Validate Payload').first().json;
return [{
  json: {
    ...ticket,
    input_hash: payload.input_hash,
    ai_prompt: `Classify this B2B support ticket. Return JSON only, no markdown.
Email: ${ticket.customer_email}
Subject: ${ticket.subject}
Body: ${ticket.body}

Schema:
{
  "category": "billing" | "technical" | "sales" | "refund" | "other",
  "priority": "low" | "medium" | "high",
  "confidence": 0.0,
  "summary": "one sentence",
  "recommended_action": "escalate_human" | "auto_reply_template" | "monitor",
  "sentiment": "neutral" | "frustrated" | "urgent"
}`
  }
}];

const ticket = $('Insert Ticket').first().json;
const payload = $('Validate Payload').first().json;
const aiRaw = $input.first().json.text || $input.first().json.output || '';
let parsed = {};
try {
  const cleaned = String(aiRaw).replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    category: 'other',
    priority: 'medium',
    confidence: 0,
    summary: 'AI response parse failed',
    recommended_action: 'escalate_human',
    sentiment: 'neutral'
  };
}
const keywords = ['refund', 'charged twice', 'down', 'outage', 'cancel immediately'];
const combined = `${ticket.subject} ${ticket.body}`.toLowerCase();
let priority = parsed.priority || 'medium';
if (keywords.some((k) => combined.includes(k)) && priority !== 'high') {
  priority = 'high';
}
const confidence = Number(parsed.confidence) || 0;
let assigned_to = null;
if (confidence < 0.6) {
  assigned_to = 'ai_low_confidence';
}
const notify_slack = priority === 'high' && confidence >= 0.6;
return [{
  json: {
    ticket_id: ticket.id,
    customer_email: ticket.customer_email,
    subject: ticket.subject,
    body: ticket.body,
    input_hash: payload.input_hash,
    category: parsed.category || 'other',
    priority,
    confidence_score: confidence,
    ai_summary: parsed.summary || '',
    assigned_to,
    status: 'classified',
    notify_slack,
    ai_output: parsed,
    model_version: 'gpt-4o-mini'
  }
}];

